arguments.file_text:
@if (Products is null || Products.Count == 0)
{
    <div class="text-center text-muted py-5">
        <h5>No products found</h5>
        <p>Try adjusting your filters.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>
            @foreach (var page in PageNumbers)
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> PageNumbers => Enumerable.Range(1, TotalPages);

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}

<div class="row">
    <div class="col-md-3">
        <CatalogSidebar Categories="_categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />
    </div>
    <div class="col-md-9">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <p class="mt-2 text-muted">Loading products...</p>
            </div>
        }
        else if (_result is not null)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="TotalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    /// <summary>
    /// Raised when a product card is clicked, allowing a parent layout to handle navigation.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load categories: {ex.Message}";
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }
}

